const express = require('express');
var session = require("express-session");
const port = 3001; //set to 80 if not using HTTPS
const app = express();
app.use(session({ secret: 'secret', cookie:{ maxAge: 500 } }));

const randomNum = function() {
    return Math.floor(Math.random() * 900000 +100000); //random number generated between 10,000 and 99,999
  };

const verify = async (code) => {
    const sessionData = app.sessions;
    if(sessionData[app.session] !== undefined){
        if(sessionData[app.session].code == code){ //validates that the correct 6 digit number is entered
            console.log('The entered code: ' + code + ' is correct!'); //only for testing, remove later 
            return true;
        }else{
            throw Error(); 
        }
    }
};

  app.get('/', function (req, res) {
    res.send('Hello World!');
  });

  app.post('/check-code', async (request, response) => {

    let newCode =  randomNum(); 
    sessionData[app.session] = {}; //creates a unique session
    sessionData[app.session].code = newCode; //pushes 6 digit code into session object
    
    //send code to user

    console.log(newCode + " has been sent"); //only for testing, remove later
    response.end();

  });

  app.post('/verify-code', async (request, response) => {

    let verified = await verify(request.body); //waits and waits for the async function to return. If it returns true, then the code is verified
    if (!verified){
        console.log('The entered code was incorrect.'); //only for testing, remove later 
    }
    
  });

  app.listen(port, () => {
    console.log(`Example app listening at http://localhost:${port}`);
  });